#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#ifndef DEVICE
#define DEVICE 0
#endif

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100
#define FACTOR_CHIP  0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

float t_chip      = 0.0005f;
float chip_height = 0.016f;
float chip_width  = 0.016f;
float amb_temp    = 80.0f;

void fatal(char *s) {
    fprintf(stderr, "Error: %s\n", s);
}

void usage(int argc, char **argv)
{
    (void)argc;
    fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile> [-p platform] [-d device]\n", argv[0]);
    fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
    fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");
    fprintf(stderr, "\t<iteration> - number of iterations\n");
    fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
    fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<outputFile - output file\n");
    exit(1);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i, j, k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++)
            for (k = 0; k <= layers - 1; k++) {
                if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
                if (feof(fp)) fatal("not enough lines in file");
                if ((sscanf(str, "%f", &val) != 1)) fatal("invalid file format");
                vect[i * grid_cols + j + k * grid_rows * grid_cols] = val;
            }

    fclose(fp);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i, j, k, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++)
            for (k = 0; k < layers; k++) {
                sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j + k * grid_rows * grid_cols]);
                fputs(str, fp);
                index++;
            }

    fclose(fp);
}

void computeTempCPU(float *pIn, float* tIn, float *tOut,
        int nx, int ny, int nz, float Cap,
        float Rx, float Ry, float Rz,
        float dt, float amb_temp, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int c, w, e, n, s, b, t;
    int x, y, z;
    int i = 0;
    do {
        for (z = 0; z < nz; z++)
            for (y = 0; y < ny; y++)
                for (x = 0; x < nx; x++) {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c] * cc + tIn[n] * cn + tIn[s] * cs + tIn[e] * ce + tIn[w] * cw + tIn[t] * ct + tIn[b] * cb + (dt / Cap) * pIn[c] + ct * amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    } while (i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0f;
    int i;
    for (i = 0; i < len; i++) {
        err += (arr1[i] - arr2[i]) * (arr1[i] - arr2[i]);
    }
    return (float)sqrt(err / len);
}

static void hotspotOpt1_omp(
    float *p, float *tmp_17, float *x_2, float elem_16,
    int x_4, int item_8, int data_7,
    float item_1, float val_6,
    float var_9, float item_3,
    float item_15, float elem_5,
    float x_11)
{
    float x_13 = 80.0f;
    int item_0 = x_4 * item_8;

    #pragma omp parallel for collapse(2)
    for (int j = 0; j < item_8; j++) {
        for (int i = 0; i < x_4; i++) {
            int c = i + j * x_4;

            int W = (0 == i) ? c : c - 1;
            int E = (x_4 - 1 == i) ? c : c + 1;
            int N = (0 == j) ? c : c - x_4;
            int S = (item_8 - 1 == j) ? c : c + x_4;

            float data_14, tmp_10, data_12;
            data_14 = tmp_10 = tmp_17[c];
            data_12 = tmp_17[c + item_0];
            x_2[c] = x_11 * tmp_10 + val_6 * tmp_17[W] + item_1 * tmp_17[E] + item_3 * tmp_17[S]
                   + var_9 * tmp_17[N] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c] + item_15 * x_13;
            c = c + item_0;
            W = W + item_0;
            E = E + item_0;
            N = N + item_0;
            S = S + item_0;

            for (int k = 1; data_7 - 1 > k; ++k) {
                data_14 = tmp_10;
                tmp_10 = data_12;
                data_12 = tmp_17[c + item_0];
                x_2[c] = x_11 * tmp_10 + val_6 * tmp_17[W] + item_1 * tmp_17[E] + item_3 * tmp_17[S]
                       + var_9 * tmp_17[N] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c] + item_15 * x_13;
                c = c + item_0;
                W = W + item_0;
                E = E + item_0;
                N = N + item_0;
                S = S + item_0;
            }
            data_14 = tmp_10;
            tmp_10 = data_12;
            x_2[c] = x_11 * tmp_10 + val_6 * tmp_17[W] + item_1 * tmp_17[E] + item_3 * tmp_17[S]
                   + var_9 * tmp_17[N] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c] + item_15 * x_13;
        }
    }
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols = 0;
    int numRows = 0;
    int layers = 0;

    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    int cur_arg;
    for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (0 == strcmp(argv[cur_arg], "-h")) {
            usage(argc, argv);
        } else if (0 == strcmp(argv[cur_arg], "-n")) {
            if (cur_arg + 1 <= argc) {
                numCols = numRows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (0 == strcmp(argv[cur_arg], "-l")) {
            if (cur_arg + 1 <= argc) {
                layers = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (0 == strcmp(argv[cur_arg], "-i")) {
            if (cur_arg + 1 <= argc) {
                iterations = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (0 == strcmp(argv[cur_arg], "-f")) {
            if (cur_arg + 3 <= argc) {
                pfile = argv[cur_arg + 1];
                tfile = argv[cur_arg + 2];
                ofile = argv[cur_arg + 3];
                cur_arg = cur_arg + 3;
            }
        } else if (0 == strcmp(argv[cur_arg], "-p")) {
            if (cur_arg + 1 <= argc) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (0 == strcmp(argv[cur_arg], "-d")) {
            if (cur_arg + 1 <= argc) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    if (0 == numCols || 0 == layers || 0 == iterations || NULL == pfile) {
        usage(argc, argv);
    }

    (void)platform_id_inuse;
    (void)device_id_inuse;

    float dx = chip_height / numRows;
    float dy = chip_width / numCols;
    float dz = t_chip / layers;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx = dy / (2.0f * K_SI * t_chip * dx);
    float Ry = dx / (2.0f * K_SI * t_chip * dy);
    float Rz = dz / (K_SI * dx * dy);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt = PRECISION / max_slope;

    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int size = numCols * numRows * layers;
    float *tIn      = (float*)calloc(size, sizeof(float));
    float *pIn      = (float*)calloc(size, sizeof(float));
    float *tempCopy = (float*)malloc(size * sizeof(float));
    float *tempOut  = (float*)calloc(size, sizeof(float));
    int count = size;

    readinput(tIn, numRows, numCols, layers, tfile);
    readinput(pIn, numRows, numCols, layers, pfile);
    memcpy(tempCopy, tIn, size * sizeof(float));

    printf("num_devices = %d\n", 1);
    printf(" \n Device is  OpenMP CPU \n");
    printf(" OpenMP \n");

    float *d_a = tIn;
    float *d_b = pIn;
    float *d_c = tempOut;

    for (int j = 0; iterations > j; j++) {
        hotspotOpt1_omp(
            d_b, d_a, d_c, stepDivCap,
            numCols, numRows, layers,
            ce, cw, cn, cs, ct, cb, cc
        );

        float *temp = d_a;
        d_a = d_c;
        d_c = temp;
    }

    memcpy(tempOut, d_c, sizeof(float) * count);

    float *answer = (float*)calloc(size, sizeof(float));
    computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
    float acc = accuracy(tempOut, answer, numRows * numCols * layers);
    printf("Accuracy: %e\n", acc);

    writeoutput(tempOut, numRows, numCols, layers, ofile);

    free(answer);
    free(tempOut);
    free(tempCopy);
    free(pIn);
    free(tIn);

    return 0;
}
